class Solution:
    def concatHex36(self, n):
        digs = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ'
        def conv(x, base):
            if x == 0:
                return '0'
            out = ''
            while x > 0:
                out = digs[x % base] + out
                x //= base
            return out
        return conv(n * n, 16) + conv(n * n * n, 36)

