class Solution:
    def concatHex36(self, n):
        D = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ'
        def f(x, b):
            r = []
            while x:
                r.append(D[x % b])
                x //= b
            return ''.join(reversed(r)) or '0'
        return f(n * n, 16) + f(n * n * n, 36)

