var concatHex36 = function(n) {
    const D = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ';
    const f = (x, b) => {
        let r = '';
        while (x > 0) { r = D[x % b] + r; x = Math.floor(x / b); }
        return r || '0';
    };
    return f(n * n, 16) + f(n * n * n, 36);
};
